use postgres::{Client, NoTls};

fn search_users_by_email(email: &str) -> Vec<User> {
    let mut client = Client::connect("host=localhost user=postgres password=password dbname=mydb", NoTls).unwrap();

    // Build the query dynamically
    let query = format!("SELECT * FROM users WHERE email = '{}'", email);

    // Execute the query and return the results as a Vec
    client.query(query, &[])
        .map(|row| User { id: row.get(0), name: row.get(1) })
        .collect()
}